# --- bootstrap.py -----------------------------------------------------------
# Scénario Bootstrap (E/V/R) minimal

from __future__ import annotations
from pathlib import Path
import webbrowser
from typing import Dict, Any

from erk_state import (
    load_fractal_state,
    is_system_config_complete,
    is_project_config_complete,
)

from erk_compile import render_page  # Adapter si API différente


def decide_bootstrap_target(fractal_state: Dict[str, Any]) -> str:
    if not is_system_config_complete(fractal_state):
        return "config_web.html"
    if not is_project_config_complete(fractal_state):
        return "project_config.html"
    return "index.html"


def run_bootstrap(open_in_browser: bool = True) -> Path:
    fractal_state = load_fractal_state()
    target = decide_bootstrap_target(fractal_state)

    output_path = Path(__file__).resolve().parent / target

    render_page(
        template_name=target,
        output_path=output_path,
        state=fractal_state,
    )

    if open_in_browser:
        try:
            webbrowser.open(output_path.resolve().as_uri())
        except Exception:
            pass

    return output_path


def main() -> None:
    run_bootstrap(open_in_browser=True)


if __name__ == "__main__":
    main()
EOF


