🔧 1. Réécrire complètement erk_state.py avec ProjectState
bashCopier le codecd /Users/nathalie/Dropbox/____BIG_BOFF___/PROJETS/PRO/EURKAI/WEB

cat << 'EOF' > erk_state.py
# --- erk_state.py -----------------------------------------------------------
# Etat fractal minimal (adapté provisoirement depuis .env)
# Source logique interne = fractal_state (pas .env)
#
# Compatibilité :
#   - BASE_DIR           : utilisé par d'autres modules
#   - ProjectState       : attendu par erk_page_factory (type / container)
#   - load_project_state : wrapper historique -> renvoie un ProjectState

from __future__ import annotations
from pathlib import Path
from typing import Any, Dict

BASE_DIR = Path(__file__).resolve().parent
ENV_PATH = BASE_DIR / ".env"


# ---------------------------------------------------------------------------
#  LOW-LEVEL : lecture .env  (backend technique provisoire)
# ---------------------------------------------------------------------------

def _parse_env_file(path: Path = ENV_PATH) -> Dict[str, str]:
    env: Dict[str, str] = {}
    if not path.exists():
        return env
    text = path.read_text(encoding="utf-8")
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        if "=" not in line:
            continue
        key, value = line.split("=", 1)
        env[key.strip()] = value.strip()
    return env


# ---------------------------------------------------------------------------
#  FRACTAL STATE : interface officielle
# ---------------------------------------------------------------------------

def load_fractal_state() -> Dict[str, Any]:
    """
    Retourne l'état fractal minimal du projet.

    Pour l'instant :
    - hydraté à partir de .env (backend technique)
    - expose un objet "config_runtime" structuré par domaines.
    """
    env = _parse_env_file()

    config_runtime = {
        "database": {
            "engine": env.get("DB_ENGINE", ""),
            "host": env.get("DB_HOST", ""),
            "name": env.get("DB_NAME", ""),
            "user": env.get("DB_USER", ""),
            "password": env.get("DB_PASSWORD", ""),
        },
        "ai_provider": {
            "provider": env.get("AI_PROVIDER", ""),
            "model": env.get("AI_MODEL", ""),
        },
        "hosting": {
            "mode": env.get("HOSTING_MODE", ""),
            "base_url": env.get("HOSTING_BASE_URL", ""),
        },
        "admin": {
            "email": env.get("ADMIN_EMAIL", ""),
            "display_name": env.get("ADMIN_NAME", ""),
        },
        "project": {
            "name": env.get("PROJECT_NAME", ""),
            "slug": env.get("PROJECT_SLUG", ""),
        },
    }

    return {
        "config_runtime": config_runtime,
        "env_raw": env,
    }


# ---------------------------------------------------------------------------
#  CONTAINER : ProjectState (compatible dict + attributs)
# ---------------------------------------------------------------------------

class ProjectState:
    """
    Container pour l'état de projet.

    - state.fractal_state      : dict complet fractal
    - state.config_runtime     : sous-dict config
    - state.env                : env_raw
    - state.base_dir           : racine WEB
    - state.templates_dir      : dossier templates
    - state["xxx"]             : accès dict-like
    """

    def __init__(self, fractal_state: Dict[str, Any], base_dir: Path | None = None) -> None:
        self.fractal_state = fractal_state
        self.base_dir: Path = base_dir or BASE_DIR

    # Propriétés utilitaires

    @property
    def config_runtime(self) -> Dict[str, Any]:
        return self.fractal_state.get("config_runtime", {}) or {}

    @property
    def env(self) -> Dict[str, str]:
        return self.fractal_state.get("env_raw", {}) or {}

    @property
    def templates_dir(self) -> Path:
        return self.base_dir / "templates"

    # Compatibilité "dict-like"

    def __getitem__(self, key: str) -> Any:
        return self.fractal_state[key]

    def get(self, key: str, default: Any = None) -> Any:
        return self.fractal_state.get(key, default)

    def __contains__(self, key: str) -> bool:
        return key in self.fractal_state

    def __iter__(self):
        return iter(self.fractal_state)

    def items(self):
        return self.fractal_state.items()

    # Fallback sur fractal_state pour certains attributs

    def __getattr__(self, name: str) -> Any:
        # si l'attribut existe dans fractal_state, on le renvoie
        if name in self.fractal_state:
            return self.fractal_state[name]
        raise AttributeError(f"{type(self).__name__!r} object has no attribute {name!r}")


# ---------------------------------------------------------------------------
#  COMPATIBILITÉ AVEC L'ANCIEN CODE
# ---------------------------------------------------------------------------

def load_project_state() -> ProjectState:
    """
    Wrapper historique pour erk_compile / erk_page_factory :
    - ancien nom : load_project_state
    - nouvelle logique : ProjectState + fractal_state
    """
    fractal = load_fractal_state()
    return ProjectState(fractal, BASE_DIR)


# ---------------------------------------------------------------------------
#  VALIDATION MINIMALE (V de GEVR) — provisoire
# ---------------------------------------------------------------------------

def is_system_config_complete(fractal_state: Dict[str, Any]) -> bool:
    cfg = fractal_state.get("config_runtime", {})
    db = cfg.get("database", {}) or {}
    ai = cfg.get("ai_provider", {}) or {}
    hosting = cfg.get("hosting", {}) or {}

    db_ok = all(db.get(k) for k in ("engine", "name"))
    ai_ok = all(ai.get(k) for k in ("provider",))
    hosting_ok = all(hosting.get(k) for k in ("base_url",))

    return db_ok and ai_ok and hosting_ok


def is_project_config_complete(fractal_state: Dict[str, Any]) -> bool:
    cfg = fractal_state.get("config_runtime", {})
    project = cfg.get("project", {}) or {}
    return all(project.get(k) for k in ("name", "slug"))
EOF


