from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Dict, Any, List
import json


BASE_DIR = Path(__file__).resolve().parent
CATALOGS_DIR = BASE_DIR / "catalogs"
ENV_PATH = BASE_DIR / ".env"


def load_env() -> Dict[str, str]:
    env: Dict[str, str] = {}
    if not ENV_PATH.exists():
        return env

    text = ENV_PATH.read_text(encoding="utf-8")
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        if "=" not in line:
            continue
        key, value = line.split("=", 1)
        env[key.strip()] = value.strip().strip('"')
    return env


def _load_json_catalog(filename: str) -> Dict[str, Any]:
    path = CATALOGS_DIR / filename
    if not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _resolve_site_context() -> Dict[str, Any]:
    projects = _load_json_catalog("projects.json")
    interface_pages = _load_json_catalog("interface_pages.json")
    products = _load_json_catalog("products_website.json")

    project_key = "Object:Project:Eurekai"
    page_key = "Object:Interface:Page:Index"
    product_key = "Product:DigitalProduct:Website:Eurekai_website"

    project = projects.get(project_key, {})
    page = interface_pages.get(page_key, {})
    _product = products.get(product_key, {})

    project_id = project.get("IdentityDefinitionPlane", {}) or {}
    project_view = project.get("ViewDefinitionPlane", {}) or {}
    page_id = page.get("IdentityDefinitionPlane", {}) or {}

    project_name = (
        project_id.get("name")
        or project_id.get("code")
        or "PROJECT"
    )
    page_title = (
        page_id.get("title")
        or page_id.get("code")
        or "Index"
    )

    site_title = (
        project_view.get("site_title")
        or project_name
    )
    site_tagline = project_view.get("site_tagline") or ""

    return {
        "project_name": str(project_name),
        "page_title": str(page_title),
        "site_title": str(site_title),
        "site_tagline": str(site_tagline),
    }


def _resolve_db_options() -> List[Dict[str, str]]:
    db_catalog = _load_json_catalog("db_engines.json")
    options: List[Dict[str, str]] = []

    for _key, db in db_catalog.items():
        ident = db.get("IdentityDefinitionPlane", {}) or {}
        code = ident.get("code")
        label = ident.get("label") or code
        if not code:
            continue
        options.append(
            {
                "value": code,
                "label": label,
                "input_type": "checkbox",
                "group": "DB_TYPE"
            }
        )
    return options


def _resolve_ai_options() -> Dict[str, Any]:
    ai_catalog = _load_json_catalog("ai_providers.json")
    provider_options = []
    model_options = []

    for _key, provider in ai_catalog.items():
        ident = provider.get("IdentityDefinitionPlane", {}) or {}
        view = provider.get("ViewDefinitionPlane", {}) or {}
        code = ident.get("code")
        label = ident.get("label") or code
        if not code:
            continue

        provider_options.append(
            {
                "value": code,
                "label": label,
                "input_type": "checkbox",
                "group": "AI_PROVIDER"
            }
        )

        models = view.get("models", []) or []
        for model in models:
            m_code = model.get("code")
            m_label = model.get("label") or m_code
            if not m_code:
                continue
            # Pour l'instant, on ne filtre pas par provider côté rendu
            model_options.append(
                {
                    "value": m_code,
                    "label": f"{label} — {m_label}",
                    "input_type": "checkbox",
                    "group": "AI_MODEL",
                    "provider": code
                }
            )

    return {
        "providers": provider_options,
        "models": model_options
    }


@dataclass
class ProjectState:
    env: Dict[str, str]
    base_dir: Path
    catalogs_dir: Path
    project_name: str
    page_title: str
    site_title: str
    site_tagline: str
    db_type_options: list
    ai_provider_options: list
    ai_model_options: list

    @property
    def templates_dir(self) -> Path:
        return self.base_dir / "templates"


