3️⃣ Étendre le template engine avec {{ options:KEY }}
On ajoute une directive qui prend une liste d’options dans context[KEY] et les rend en HTML (checkbox par défaut, radio si input_type == "radio", select si input_type == "select").
bashCopier le codecd /Users/nathalie/Dropbox/____BIG_BOFF___/PROJETS/PRO/EURKAI/WEB

cat << 'EOF' > template_engine.py
from __future__ import annotations

from pathlib import Path
from typing import Dict, Any, List
import re


BASE_DIR = Path(__file__).resolve().parent
ROOT_DIR = BASE_DIR.parent
RESOURCES_DIR = ROOT_DIR / "RESOURCES"
DOCS_DIR = RESOURCES_DIR / "DOCS"

PROJECT_TEMPLATES_DIR = BASE_DIR / "templates"
DEFAULT_TEMPLATES_DIR = DOCS_DIR / "TEMPLATES" / "web"


INCLUDE_RE = re.compile(r"{{\s*include:([^}]+)\s*}}")
INCLUDE_OPT_RE = re.compile(r"{{\s*include\?:([^}]+)\s*}}")
VAR_RE = re.compile(r"{{\s*var:([^}]+)\s*}}")
FIELD_RE = re.compile(r"{{\s*field:([^}]+)\s*}}")
OPTIONS_RE = re.compile(r"{{\s*options:([^}]+)\s*}}")


def _load_template_file(path: Path) -> str:
    if not path.exists():
        raise FileNotFoundError(f"Template non trouvé: {path}")
    return path.read_text(encoding="utf-8")


def _load_template(name: str) -> str:
    project_path = PROJECT_TEMPLATES_DIR / name
    if project_path.exists():
        return _load_template_file(project_path)

    default_path = DEFAULT_TEMPLATES_DIR / name
    if default_path.exists():
        return _load_template_file(default_path)

    raise FileNotFoundError(
        f"Template '{name}' introuvable ni dans {PROJECT_TEMPLATES_DIR} "
        f"ni dans {DEFAULT_TEMPLATES_DIR}"
    )


def _render_includes(raw: str) -> str:

    def replace_include(match: re.Match) -> str:
        filename = match.group(1).strip()
        return _load_template(filename)

    def replace_include_opt(match: re.Match) -> str:
        filename = match.group(1).strip()
        try:
            return _load_template(filename)
        except FileNotFoundError:
            return ""

    content = raw

    while True:
        new_content = INCLUDE_RE.sub(replace_include, content)
        new_content = INCLUDE_OPT_RE.sub(replace_include_opt, new_content)
        if new_content == content:
            break
        content = new_content

    return content


def _render_vars(content: str, context: Dict[str, Any]) -> str:

    def replace_var(match: re.Match) -> str:
        key = match.group(1).strip()
        value = context.get(key, "")
        return str(value) if value is not None else ""

    return VAR_RE.sub(replace_var, content)


def _render_fields(content: str, context: Dict[str, Any]) -> str:
    ui_mode = context.get("UI_MODE", "display")

    def replace_field(match: re.Match) -> str:
        key = match.group(1).strip()
        value = context.get(key, "")

        if ui_mode == "form":
            val_attr = f' value="{value}"' if value not in (None, "") else ""
            return f'<input name="{key}"{val_attr} />'

        if key in context and value not in (None, ""):
            return str(value)

        return f'<input name="{key}" />'

    return FIELD_RE.sub(replace_field, content)


def _render_options(content: str, context: Dict[str, Any]) -> str:
    ui_mode = context.get("UI_MODE", "display")

    def replace_options(match: re.Match) -> str:
        key = match.group(1).strip()
        options = context.get(key, [])
        if not isinstance(options, list):
            return ""

        # Pour le moment, options ont la forme :
        # { "value": "...", "label": "...", "input_type": "checkbox"|"radio"|"select", "group": "..." }
        if ui_mode not in ("form", "edit"):
            # En display, on se contente de lister les valeurs sélectionnées (à faire plus tard)
            labels = [opt.get("label") or opt.get("value") for opt in options]
            return ", ".join(labels)

        html_parts: List[str] = []
        # On rend checkbox / radio. Le cas "select" pourra être ajouté plus tard.
        for opt in options:
            value = opt.get("value", "")
            label = opt.get("label", value)
            input_type = opt.get("input_type", "checkbox")
            group_name = opt.get("group") or key

            if input_type in ("checkbox", "radio"):
                multiple = "[]" if input_type == "checkbox" else ""
                html_parts.append(
                    f'<label><input type="{input_type}" '
                    f'name="{group_name}{multiple}" value="{value}" /> {label}</label>'
                )
            else:
                # fallback simple
                html_parts.append(label)

        return "<br />\n".join(html_parts)

    return OPTIONS_RE.sub(replace_options, content)


def render_template(name: str, context: Dict[str, Any] | None = None) -> str:
    if context is None:
        context = {}

    raw = _load_template(name)
    with_includes = _render_includes(raw)
    with_vars = _render_vars(with_includes, context)
    with_fields = _render_fields(with_vars, context)
    final = _render_options(with_fields, context)
    return final


def render_to_file(name: str, output_path: Path, context: Dict[str, Any] | None = None) -> Path:
    html = render_template(name, context)
    output_path.write_text(html, encoding="utf-8")
    return output_path
EOF


