from __future__ import annotations

from pathlib import Path
from typing import Dict, Any, List
import json

from erk_state import load_project_state, BASE_DIR
from template_engine import render_to_file


INDEX_CONFIG_PATH = BASE_DIR / "catalogs" / "index_config.json"


def _build_body_html_from_catalogs() -> str:
    if not INDEX_CONFIG_PATH.exists():
        return ""

    try:
        data: Dict[str, Any] = json.loads(INDEX_CONFIG_PATH.read_text(encoding="utf-8"))
    except Exception:
        return ""

    parts: List[str] = []

    def render_body(body_key: str) -> None:
        body = data.get(body_key, {})
        view = body.get("ViewDefinitionPlane", {}) or {}
        sections = view.get("element_list", []) or []
        for section_key in sections:
            section = data.get(section_key, {})
            s_id = section.get("IdentityDefinitionPlane", {}) or {}
            s_view = section.get("ViewDefinitionPlane", {}) or {}
            title = s_id.get("name") or s_id.get("code") or section_key

            parts.append("<section>")
            parts.append(f"<h3>{title}</h3>")

            fields = s_view.get("element_list", []) or []
            for field_key in fields:
                field = data.get(field_key, {})
                f_id = field.get("IdentityDefinitionPlane", {}) or {}
                f_view = field.get("ViewDefinitionPlane", {}) or {}

                label = f_id.get("label") or f_id.get("key") or field_key
                key = f_id.get("key") or field_key
                input_type = f_view.get("input_type", "text")
                options_source = f_view.get("options_source")

                parts.append("<div>")
                parts.append(f"<label>{label}</label><br />")

                if input_type == "enum" and options_source:
                    # options:OPTIONS_SOURCE sera résolu plus tard par template_engine
                    parts.append(f"{{{{ options:{options_source} }}}}")
                else:
                    # field:KEY sera résolu plus tard par template_engine
                    parts.append(f"{{{{ field:{key} }}}}")

                parts.append("</div><br />")

            parts.append("</section>")
            parts.append("<hr />")

    # Pour l'instant, on rend les deux corps à la suite :
    #  - SystemConfigBody (config globale)
    #  - ProjectConfigBody (config projet)
    render_body("Content:WebContent:SystemConfigBody")
    render_body("Content:WebContent:ProjectConfigBody")

    return "\n".join(parts)


def compile_page(template_name: str, output_name: str | None = None) -> Path:
    state = load_project_state()

    if output_name is None:
        output_name = template_name

    output_path = BASE_DIR / output_name

    context: Dict[str, Any] = {}

    context["PROJECT_NAME"] = state.project_name
    context["PAGE_TITLE"] = state.page_title
    context["SITE_TITLE"] = state.site_title
    context["SITE_TAGLINE"] = state.site_tagline

    context["project_name"] = state.project_name
    context["page_title"] = state.page_title

    # Mode formulaire global pour la config initiale
    context["UI_MODE"] = "form"

    # Bundles d'options (DB / IA)
    context["DB_TYPE_OPTIONS"] = state.db_type_options
    context["AI_PROVIDER_OPTIONS"] = state.ai_provider_options
    context["AI_MODEL_OPTIONS"] = state.ai_model_options

    # Contenu de la page entièrement généré à partir des catalogues
    context["BODY_HTML"] = _build_body_html_from_catalogs()

    return render_to_file(template_name, output_path, context=context)
